// First we create a variable
let z = function () {
  this.a = 1;
  this.b = 2;
}

// Then, via the constructor, z becomes a prototype
const i = new z(); // now we have a z prototype, where a = 1 and b = 2

// Next, add properties to the z prototype
z.prototype.c = 3;
z.prototype.d = 'Hello' + this.a;

// Now let's see what each one outputs
console.log(i.a); // 1
console.log(i.b); // 2
console.log(i.c); // 3 — i didn't have this, so it walks up the prototype chain to find it
console.log(i.d); // Hello 1 — same deal, found via the prototype chain
console.log(i.e); // walked the whole chain, found nothing, so it returns undefined

